'use client';

import React, { useMemo, useState } from 'react';
import { 
  Users, 
  Trash2, 
  Search, 
  Loader2, 
  User as UserIcon,
  ShieldAlert,
  Mail,
  MapPin
} from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { useCollection, useFirestore, useMemoFirebase, useUser } from '@/firebase';
import { collection, doc, deleteDoc } from 'firebase/firestore';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { 
  Table, 
  TableBody, 
  TableCell, 
  TableHead, 
  TableHeader, 
  TableRow 
} from '@/components/ui/table';
import { 
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from '@/components/ui/alert-dialog';
import { useToast } from '@/hooks/use-toast';
import { countries } from '@/lib/countries';

export default function AdminUsersPage() {
  const firestore = useFirestore();
  const { user: currentUser } = useUser();
  const { toast } = useToast();
  const [searchTerm, setSearchTerm] = useState('');

  const usersQuery = useMemoFirebase(() => {
    if (!firestore) return null;
    return collection(firestore, 'users');
  }, [firestore]);

  const { data: users, isLoading } = useCollection(usersQuery);

  const filteredUsers = useMemo(() => {
    if (!users) return [];
    // Filter out anonymous/incomplete records and filter by search term
    return users.filter(u => {
      const isRegistered = u.email && u.email.includes('@');
      const matchesSearch = 
        u.email?.toLowerCase().includes(searchTerm.toLowerCase()) || 
        u.name?.toLowerCase().includes(searchTerm.toLowerCase());
      return isRegistered && matchesSearch;
    });
  }, [users, searchTerm]);

  const handleDeleteUser = async (userId: string, userEmail: string) => {
    if (!firestore) return;
    try {
      // NOTE: This only deletes the Firestore profile. 
      // Deleting the Auth user would require Firebase Admin SDK which is not available in client code.
      await deleteDoc(doc(firestore, 'users', userId));
      toast({
        title: "User Profile Deleted",
        description: `Successfully removed profile for ${userEmail} from Firestore.`,
      });
    } catch (error: any) {
      toast({
        variant: "destructive",
        title: "Delete Failed",
        description: error.message,
      });
    }
  };

  if (isLoading) {
    return (
      <div className="flex h-[40vh] items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      <Card className="shadow-xl border-0 rounded-[2rem] overflow-hidden bg-white">
        <CardHeader className="py-8 px-10 border-b border-slate-50 bg-slate-50/30">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-primary/10 rounded-2xl text-primary">
                <Users className="w-6 h-6" />
              </div>
              <div>
                <CardTitle className="text-xl font-bold text-[#1e293b]">User Management</CardTitle>
                <p className="text-xs font-medium text-muted-foreground mt-1 uppercase tracking-wider">
                  Managing {filteredUsers.length} active registered accounts
                </p>
              </div>
            </div>
            
            <div className="relative w-full md:w-80">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <Input 
                placeholder="Search by name or email..." 
                className="pl-12 rounded-xl h-12 border-slate-200 bg-white focus:ring-2 focus:ring-primary/20"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>
        </CardHeader>
        <CardContent className="p-0">
          <Table>
            <TableHeader className="bg-slate-50">
              <TableRow className="hover:bg-transparent border-0">
                <TableHead className="px-10 h-14 text-[11px] font-black uppercase tracking-widest text-slate-400">User</TableHead>
                <TableHead className="h-14 text-[11px] font-black uppercase tracking-widest text-slate-400">Contact</TableHead>
                <TableHead className="h-14 text-[11px] font-black uppercase tracking-widest text-slate-400">Location</TableHead>
                <TableHead className="h-14 text-[11px] font-black uppercase tracking-widest text-slate-400 text-right pr-10">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredUsers.length > 0 ? (
                filteredUsers.map((user) => (
                  <TableRow key={user.id} className="hover:bg-slate-50/50 transition-colors border-b border-slate-50">
                    <TableCell className="px-10 py-6">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center overflow-hidden border border-slate-200 shadow-sm">
                          {user.photoURL ? (
                            <img src={user.photoURL} alt={user.name} className="w-full h-full object-cover" />
                          ) : (
                            <UserIcon className="w-5 h-5 text-slate-400" />
                          )}
                        </div>
                        <div className="flex flex-col">
                          <span className="text-sm font-bold text-[#1e293b]">{user.name || 'Anonymous'}</span>
                          <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">UID: {user.id.slice(0, 8)}...</span>
                        </div>
                      </div>
                    </TableCell>
                    <TableCell>
                      <div className="flex items-center gap-2">
                        <Mail className="w-3.5 h-3.5 text-primary" />
                        <span className="text-sm font-medium text-slate-600">{user.email}</span>
                      </div>
                    </TableCell>
                    <TableCell>
                      <div className="flex items-center gap-2">
                        <MapPin className="w-3.5 h-3.5 text-accent" />
                        <span className="text-sm font-bold text-slate-600">
                          {countries.find(c => c.code === user.country)?.name || user.country || 'N/A'}
                        </span>
                      </div>
                    </TableCell>
                    <TableCell className="text-right pr-10">
                      <AlertDialog>
                        <AlertDialogTrigger asChild>
                          <Button 
                            variant="ghost" 
                            size="icon" 
                            className="h-10 w-10 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-xl"
                          >
                            <Trash2 className="w-4.5 h-4.5" />
                          </Button>
                        </AlertDialogTrigger>
                        <AlertDialogContent className="rounded-[2rem] border-0 shadow-2xl p-10 bg-white">
                          <AlertDialogHeader>
                            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-2xl flex items-center justify-center mb-6 shadow-inner mx-auto md:mx-0">
                              <ShieldAlert className="w-8 h-8" />
                            </div>
                            <AlertDialogTitle className="text-2xl font-black text-[#1e293b]">Confirm Deletion</AlertDialogTitle>
                            <AlertDialogDescription className="text-sm font-medium text-slate-500 leading-relaxed pt-2">
                              You are about to delete the Firestore profile for <span className="font-bold text-[#1e293b]">{user.email}</span>. This action will remove their profile and associated data from the database.
                            </AlertDialogDescription>
                          </AlertDialogHeader>
                          <AlertDialogFooter className="mt-10 gap-3">
                            <AlertDialogCancel className="rounded-xl border-slate-200 h-12 px-6 font-bold text-slate-600 hover:bg-slate-50">
                              Cancel
                            </AlertDialogCancel>
                            <AlertDialogAction 
                              onClick={() => handleDeleteUser(user.id, user.email)}
                              className="rounded-xl bg-red-500 hover:bg-red-600 text-white h-12 px-8 font-bold shadow-lg shadow-red-100"
                            >
                              Delete Account
                            </AlertDialogAction>
                          </AlertDialogFooter>
                        </AlertDialogContent>
                      </AlertDialog>
                    </TableCell>
                  </TableRow>
                ))
              ) : (
                <TableRow>
                  <TableCell colSpan={4} className="h-60 text-center">
                    <div className="flex flex-col items-center justify-center gap-3">
                      <Users className="w-12 h-12 text-slate-200" />
                      <p className="text-sm font-bold text-slate-300 uppercase tracking-widest">No users found</p>
                    </div>
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
    </div>
  );
}
